const items = $input.all();
return items.map(item => {
    const data = item.json;
    if (!data.name) return item; // Пропуск пустых айтемов от GitHub

    const updatedWorkflow = {
        nodes: data.nodes,
        connections: data.connections,
        name: data.name,
        updatedAt: new Date().toISOString()
    };

    const base64Content = Buffer.from(JSON.stringify(updatedWorkflow, null, 2)).toString('base64');
    const fileName = `${data.compareKey}-${new Date().toISOString().split('T')[0]}.json`;

    const body = {
        message: data.sha ? `Update ${data.compareKey}` : `Create backup ${data.compareKey}`,
        content: base64Content,
        branch: 'main'
    };

    if (data.sha) { body.sha = data.sha; } // Добавляем SHA только для обновления

    return {
        json: {
            githubBody: body,
            url: `https://api.github.com/repos/MarinaKirzner/test_backup/contents/${encodeURIComponent(fileName)}`
        }
    };
});

const items = $input.all();

// Фильтруем пустые айтемы, которые приходят из GitHub при включенном Always Output Data
const validItems = items.filter(item => item.json && item.json.name);

// Если айтемов нет (пустой репозиторий), возвращаем входные данные от воркфлоу, чтобы создать их
if (validItems.length === 0) {
    // В этом случае нам нужно забрать данные из ноды ПЕРЕД Гитхабом
    // Но проще всего добавить проверку внутри map
}

return items.map(item => {
    const data = item.json;

    // ПРЕДОХРАНИТЕЛЬ: если данных нет, просто возвращаем айтем как есть
    if (!data || !data.name) return item;

    let name = data.name;
    let compareKey = name;

    if (name.includes('-20')) {
        compareKey = name.split('-20')[0].trim();
    } else {
        compareKey = name.replace('.json', '');
    }

    // Собираем тело для GitHub
    // Здесь берем данные воркфлоу. Убедитесь, что nodes/connections есть в data
    const base64Content = Buffer.from(JSON.stringify(data, null, 2)).toString('base64');

    const body = {
        message: data.sha ? `Update ${compareKey}` : `Create backup of ${compareKey}`,
        content: base64Content,
        branch: 'main'
    };

    if (data.sha) {
        body.sha = data.sha;
    }

    const fileName = name.endsWith('.json') ? name : `${name}.json`;
    const url = `https://api.github.com/repos/MarinaKirzner/test_backup/contents/${encodeURIComponent(fileName)}`;

    return {
        json: {
            ...data,
            githubBody: body,
            url: url,
            compareKey: compareKey
        }
    };
});

const items = $input.all();

return items.map(item => {
    let name = item.json.name;
    let compareKey = name;

    // Если в имени есть дата (например, после дефиса начинается 2026...)
    // Улучшенная логика: отрезаем всё, что после последнего дефиса, если там дата
    if (name.includes('-20')) {
        compareKey = name.split('-20')[0].trim();
    } else {
        // Если даты нет, просто убираем .json для чистоты сравнения
        compareKey = name.replace('.json', '');
    }

    return {
        json: {
            ...item.json,
            compareKey: compareKey
        }
    };
});
